import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.HttpRequest
import akka.http.scaladsl.model.StatusCodes
import akka.stream.Materializer

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem("webhook-proxy-service")
    implicit val materializer = Materializer.create()

    val route =
      path("api" / "v1" / "webhook") {
        post {
          entity(as[String]) { userUrl =>
            Http().singleRequest(HttpRequest(uri = userUrl))
              .flatMap(response => response.status match {
                case StatusCodes.OK => Unmarshal(response.entity).to[String]
                case _ => Future.failed(new RuntimeException("Failed to fetch content"))
              })
          }
        }
      }
    Http().bindAndHandle(route, "localhost", 8080)
  }
}